import{_ as a,o as r,c as n,a3 as t}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"217. Individual Performance Measures Royal Children S","description":"","frontmatter":{"title":"217. Individual Performance Measures Royal Children S","eba":"Mental Health Services 2024-2028","topics":["preliminary"]},"headers":[],"relativePath":"ebas/mental-health/management-admin/education-pd/217-individual-performance-measures-royal-children-s.md","filePath":"ebas/mental-health/management-admin/education-pd/217-individual-performance-measures-royal-children-s.md"}'),i={name:"ebas/mental-health/management-admin/education-pd/217-individual-performance-measures-royal-children-s.md"};function s(o,e,l,d,c,m){return r(),n("div",null,[...e[0]||(e[0]=[t('<h1 id="_217-individual-performance-measures-royal-children-s" tabindex="-1">217. Individual Performance Measures Royal Children S <a class="header-anchor" href="#_217-individual-performance-measures-royal-children-s" aria-label="Permalink to &quot;217. Individual Performance Measures Royal Children S&quot;">​</a></h1><p>Hospital</p><p><strong>217.1</strong> This clause only applies to Management and Administrative Officers at Royal Children’s Hospital classified under Part 2 of <a href="/eba/ebas/mental-health/schedules/07-management-and-administrative-officers-classifications.html">Schedule 7</a> of this Agreement.</p><p><strong>217.2</strong> In the four (4) weeks prior to the commencement of a given financial year (Department Heads), and within 12 weeks of employment and on the anniversary of the appointment thereafter (all other Employees), the Employee and the Divisional Director/Department Head are to negotiate agreed performance measures for the succeeding 18-month period.</p><p><strong>217.3</strong> For the purposes of clause 217.2 above, the Employer’s “Performance Development and Staff Appraisal Scheme” shall be applied, save where there is mutual agreement to use an alternative format.</p><p><strong>217.4</strong> Individual performance measures may include: a) balancing budgets b) achieving given targets c) levels of absenteeism d) occupational health and safety e) data entry requirements f) documentation requirements g) punctuality h) percentage of patient-related work i) categories of work, levels of classification j) research; and k) conferences.</p><p><strong>217.5</strong> These measures will be subject to periodic review by the parties. Any dispute in this regard will be settled in accordance with the Dispute Settling Procedures.</p>',7)])])}const u=a(i,[["render",s]]);export{h as __pageData,u as default};
